67	void RecorderClass::logGameStart(AsciiString options)
68	{
69		if (!m_file)
70			return;
71	
72		time(&startTime);
73		UnsignedInt fileSize = ftell(m_file);
74		// move to appropriate offset
75		if (!fseek(m_file, startTimeOffset, SEEK_SET))
76		{
77			// save off start time
78			fwrite(&startTime, sizeof(time_t), 1, m_file);
79		}
80		// move back to end of stream
81	#ifdef DEBUG_CRASHING
82		Int res =
83	#endif
84			fseek(m_file, fileSize, SEEK_SET);
85		DEBUG_ASSERTCRASH(res == 0, ("Could not seek to end of file!"));
86	
87	#if defined(_DEBUG) || defined(_INTERNAL)
88		if (TheNetwork && TheGlobalData->m_saveStats)
89		{
90			//if (TheLAN)
91			{
92				unsigned long bufSize = MAX_COMPUTERNAME_LENGTH + 1;
93				char computerName[MAX_COMPUTERNAME_LENGTH + 1];
94				if (!GetComputerName(computerName, &bufSize))
95				{
96					strcpy(computerName, "unknown");
97				}
98				AsciiString statsFile = TheGlobalData->m_baseStatsDir;
99				TheFileSystem->createDirectory(statsFile);
100				statsFile.concat(computerName);
101				statsFile.concat(".txt");
102				FILE *logFP = fopen(statsFile.str(), "a+");
103				if (!logFP)
104				{
105					// try again locally
106					TheWritableGlobalData->m_baseStatsDir = TheGlobalData->getPath_UserData();
107					statsFile = TheGlobalData->m_baseStatsDir;
108					statsFile.concat(computerName);
109					statsFile.concat(".txt");
110					logFP = fopen(statsFile.str(), "a+");
111				}
112				if (logFP)
113				{
114					struct tm *t2 = localtime(&startTime);
115					fprintf(logFP, "\nGame start at %s\tOptions are %s\n", asctime(t2), options.str());
116					fclose(logFP);
117				}
118			}
119		}
