289	void RecorderClass::cleanUpReplayFile( void )
290	{
291	#if defined(_DEBUG) || defined(_INTERNAL)
292		if (TheGlobalData->m_saveStats)
293		{
294			char fname[_MAX_PATH+1];
295			strncpy(fname, TheGlobalData->m_baseStatsDir.str(), _MAX_PATH);
296			strncat(fname, m_fileName.str(), _MAX_PATH - strlen(fname));
297			DEBUG_LOG(("Saving replay to %s\n", fname));
298			AsciiString oldFname;
299			oldFname.format("%s%s", getReplayDir().str(), m_fileName.str());
300			CopyFile(oldFname.str(), fname, TRUE);
301	#ifdef DEBUG_FILE_NAME
302			AsciiString debugFname = fname;
303			debugFname.removeLastChar();
304			debugFname.removeLastChar();
305			debugFname.removeLastChar();
306			debugFname.concat("txt");
307			UnsignedInt fileSize = 0;
308			FILE *fp = fopen(DEBUG_FILE_NAME, "rb");
309			if (fp)
310			{
311				fseek(fp, 0, SEEK_END);
312				fileSize = ftell(fp);
313				fclose(fp);
314				fp = NULL;
315				DEBUG_LOG(("Log file size was %d\n", fileSize));
316			}
317	
318			const int MAX_DEBUG_SIZE = 65536;
319			if (fileSize <= MAX_DEBUG_SIZE || TheGlobalData->m_saveAllStats)
320			{
321				DEBUG_LOG(("Using CopyFile to copy %s\n", DEBUG_FILE_NAME));
322				CopyFile(DEBUG_FILE_NAME, debugFname.str(), TRUE);
323			}
324			else
325			{
326				DEBUG_LOG(("manual copy of %s\n", DEBUG_FILE_NAME));
327				FILE *ifp = fopen(DEBUG_FILE_NAME, "rb");
328				FILE *ofp = fopen(debugFname.str(), "wb");
329				if (ifp && ofp)
330				{
331					fseek(ifp, fileSize-MAX_DEBUG_SIZE, SEEK_SET);
332					char buf[4096];
333					Int len;
334					while ( (len=fread(buf, 1, 4096, ifp)) > 0 )
335					{
336						fwrite(buf, 1, len, ofp);
337					}
338					fclose(ofp);
339					fclose(ifp);
340					ifp = NULL;
341					ofp = NULL;
342				}
343				else
344				{
345					if (ifp) fclose(ifp);
346					if (ofp) fclose(ofp);
347					ifp = NULL;
348					ofp = NULL;
349				}
350			}
351	#endif // DEBUG_FILE_NAME
352		}
353	#endif
354	}
