436	/**
437	 * Do the update for the next frame of this playback.
438	 */
439	void RecorderClass::updatePlayback() {
440		cullBadCommands();	// Remove any bad commands that have been inserted by the local user that shouldn't be
441												// executed during playback.
442	
443		if (m_nextFrame == -1) {
444			// This is reached if there are no more commands to be executed.
445			return;
446		}
447		UnsignedInt curFrame = TheGameLogic->getFrame();
448		if (m_doingAnalysis)
449			curFrame = m_nextFrame;
450	
451		// While there are commands to be queued up for this frame, do it.
452		while (m_nextFrame == curFrame) {
453			appendNextCommand();	// append the next command to TheCommandQueue
454			readNextFrame();	// Read the next command's frame number for playback.
455		}
456	}
