786	void RecorderClass::writeArgument(GameMessageArgumentDataType type, const GameMessageArgumentType arg) {
787		if (type == ARGUMENTDATATYPE_INTEGER) {
788			fwrite(&(arg.integer), sizeof(arg.integer), 1, m_file);
789		} else if (type == ARGUMENTDATATYPE_REAL) {
790			fwrite(&(arg.real), sizeof(arg.real), 1, m_file);
791		} else if (type == ARGUMENTDATATYPE_BOOLEAN) {
792			fwrite(&(arg.boolean), sizeof(arg.boolean), 1, m_file);
793		} else if (type == ARGUMENTDATATYPE_OBJECTID) {
794			fwrite(&(arg.objectID), sizeof(arg.objectID), 1, m_file);
795		} else if (type == ARGUMENTDATATYPE_DRAWABLEID) {
796			fwrite(&(arg.drawableID), sizeof(arg.drawableID), 1, m_file);
797		} else if (type == ARGUMENTDATATYPE_TEAMID) {
798			fwrite(&(arg.teamID), sizeof(arg.teamID), 1, m_file);
799		} else if (type == ARGUMENTDATATYPE_LOCATION) {
800			fwrite(&(arg.location), sizeof(arg.location), 1, m_file);
801		} else if (type == ARGUMENTDATATYPE_PIXEL) {
802			fwrite(&(arg.pixel), sizeof(arg.pixel), 1, m_file);
803		} else if (type == ARGUMENTDATATYPE_PIXELREGION) {
804			fwrite(&(arg.pixelRegion), sizeof(arg.pixelRegion), 1, m_file);
805		} else if (type == ARGUMENTDATATYPE_TIMESTAMP) {
806			fwrite(&(arg.timestamp), sizeof(arg.timestamp), 1, m_file);
807		} else if (type == ARGUMENTDATATYPE_WIDECHAR) {
808			fwrite(&(arg.wChar), sizeof(arg.wChar), 1, m_file);
809		}
