981	void RecorderClass::handleCRCMessage(UnsignedInt newCRC, Int playerIndex, Bool fromPlayback)
982	{
983		if (fromPlayback)
984		{
985			//DEBUG_LOG(("RecorderClass::handleCRCMessage() - Adding CRC of %X from %d to m_crcInfo\n", newCRC, playerIndex));
986			m_crcInfo->addCRC(newCRC);
987			return;
988		}
989	
990		Int localPlayerIndex = m_crcInfo->getLocalPlayer();
991		Bool samePlayer = FALSE;
992		AsciiString playerName;
993		playerName.format("player%d", localPlayerIndex);
994		const Player *p = ThePlayerList->getNthPlayer(playerIndex);
995		if (!p || (p->getPlayerNameKey() == NAMEKEY(playerName)))
996			samePlayer = TRUE;
997		if (samePlayer || (localPlayerIndex < 0))
998		{
999			UnsignedInt playbackCRC = m_crcInfo->readCRC();
1000			//DEBUG_LOG(("RecorderClass::handleCRCMessage() - Comparing CRCs of %8.8X/%8.8X from %d\n", newCRC, playbackCRC, playerIndex));
1001			if (TheGameLogic->getFrame() > 0 && newCRC != playbackCRC && !m_crcInfo->sawCRCMismatch())
1002			{
1003				m_crcInfo->setSawCRCMismatch();
1004	
1005				//Kris: Patch 1.01 November 10, 2003 (integrated changes from Matt Campbell)
1006				// Since we don't seem to have any *visible* desyncs when replaying games, but get this warning
1007				// virtually every replay, the assumption is our CRC checking is faulty.  Since we're at the
1008				// tail end of patch season, let's just disable the message, and hope the users believe the
1009				// problem is fixed. -MDC 3/20/2003
1010				//TheInGameUI->message("GUI:CRCMismatch");
1011				DEBUG_CRASH(("Replay has gone out of sync!  All bets are off!\nOld:%8.8X New:%8.8X\nFrame:%d",
1012					playbackCRC, newCRC, TheGameLogic->getFrame()));
1013			}
1014			return;
1015		}
1016	
